// src/lib/plugin.ts
var plugin = (def) => ({
  strict: false,
  alwaysApply: false,
  ...def,
  apply: (cldAsset, ctx) => def.apply(cldAsset, ctx, ctx)
});

// src/plugins/abr.ts
var AbrPlugin = /* @__PURE__ */ plugin({
  name: "Abr",
  supports: "video",
  inferOwnOptions: {},
  props: {
    streamingProfile: true
  },
  apply: (asset, opts) => {
    if (typeof opts.streamingProfile !== "string") return {};
    asset.addTransformation(`sp_${opts.streamingProfile}`);
    return {};
  }
});
export {
  AbrPlugin
};
